import {Component,ViewEncapsulation} from '@angular/core';
import { HttpClient } from '@angular/common/http'



@Component({
    selector : 'app-image-analysis-details',
    templateUrl: './image-analysis-details.component.html',
    styleUrls:['./image-analysis-details.component.css'],
    // encapsulation: ViewEncapsulation.None
  })
  
  export class imageAnalysisDetailsComponent {

    columnsSelected:any=[];
    newcolumnlst:any=[];
    saveSuccess:boolean =false;
    msg:string;
    msgClr:string;
    showMsgState : boolean = false;
    disableTeam: boolean = false;
    constructor(private httpClient: HttpClient) {}

    ngOnInit(){
                // this.columnsSelected=['ImageName','App_name','Sub_AppName'];
// to show previos  optionsselected from DB 
                this.httpClient.get('/api/imageAnalysis/getColumnNames').subscribe(data=> {
                    if(data['response'] != 'failure'){
                        this.columnsSelected=data ['response'];
                    //   this.entDocLst= data['response'];
                      console.log("columnsSelected is ",this.columnsSelected)
                    //   this.NERDocBkp = JSON.parse(JSON.stringify( this.entDocLst ));
                    //   this.createTable();
                    }else{
                      console.warn('Could not get data from api!');
                    }
                  }, err=> {
                    console.error('Could not get data! ,'+err)
                  });


    }


    saveColumnNames(){
        console.log("while saving columns selected ",this.columnsSelected)
        let data=this.columnsSelected;
        let temp_lst: any=[];

        for (let key in data) {
            // alert(data[key])
            this.newcolumnlst.push(data[key])
            // console.log(" new colmn list is ",this.newcolumnlst)
        }
            temp_lst= [];
            this.newcolumnlst.forEach(value => {
              if(typeof value != 'string'){
                // modifiedState= true;
                temp_lst.push(value['value']);
              }else
                temp_lst.push(value);
            });
            console.log(" new temp list is ",temp_lst)
            // tagDoc['description']= temp_lst;
            // temp_lst= [];

       // console.log(" new colmn list is ",this.newcolumnlst)

        // console.log("while saving columns selected ",this.columnsSelected['value'])
        this.httpClient.post('/api/saveimageAnalysisColumnNames',temp_lst,{responseType:'text'}).subscribe(data=>{
            if(data == 'success'){
                this.msg = 'Saved successfully!';
                this.msgClr = 'green';
                this.showMsgState = true;
                console.log('savecolumns : success');
                this.ngOnInit();
                this.newcolumnlst=[];
                // temp_lst= [];
                // this.newtag=false;
                // this.envInfo=[];//to show  empty record every time when we click Add new tag 
          
              }else{
                this.msgClr = 'red';
                this.msg = 'Could not Save!';
                console.warn('Could not save by api!');
                this.ngOnInit();
                // this.newtag=false;
                // this.envInfo=[]
              }
            }, err=> {
              this.msgClr = 'red';
              this.msg = 'Could not Save due to some Error! Try again later';
              console.error('Could not save!, : '+err);


        });
        this.showMsgState = true;
        temp_lst= [];
        console.log("columnsSelected",this.columnsSelected);

        // this.httpClient()
    }

    max_count(){
        if(this.columnsSelected.length==5){
            alert("max columns  limit reached ");
        }
    }

    addElement() {
        // this.newtag=true;
        this.saveSuccess=false;
        // this.getScriptNames()
        // this.envInfo.push({entity:'',description:[]})
        // this.dataSource = new MatTableDataSource(this.envInfo);
        // console.log("this.envInfo is ",this.envInfo)
        // console.log("this.dataSource is ",this.dataSource)
    
    
      }

  }